// ═══════════════════════════════════════════════════════════════
// Veeqo Orders → Supabase Full Sync
// Replicates veeqo-orders.mjs cron logic: check-then-upsert,
// customer dedup, cost fallback, proper FK resolution
// ═══════════════════════════════════════════════════════════════

const SUPA_URL = 'https://skgzcllomhsmpbkdnqqc.supabase.co';
const SUPA_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InNrZ3pjbGxvbWhzbXBia2RucXFjIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjE0NDMwMywiZXhwIjoyMDg3NzIwMzAzfQ.1EFO3yNLwBz3Ov70tGDGCwC_bupXaBc8j-JpBZ_LuY0';

const stats = { orders_created: 0, orders_updated: 0, customers_created: 0,
  items_created: 0, shipments_created: 0, tracking_events: 0, skipped: 0, errors: 0 };
const sleep = ms => new Promise(r => setTimeout(r, ms));

// ── Supabase helpers ─────────────────────────────────────────
async function supaGet(path) {
  const res = await fetch(`${SUPA_URL}/rest/v1/${path}`, {
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
  });
  if (!res.ok) throw new Error(`GET ${res.status}: ${await res.text()}`);
  return res.json();
}

async function supaPost(table, data) {
  const res = await fetch(`${SUPA_URL}/rest/v1/${table}`, {
    method: 'POST',
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}`,
      'Content-Type': 'application/json', Prefer: 'return=representation' },
    body: JSON.stringify(data)
  });
  if (!res.ok) throw new Error(`POST ${table} ${res.status}: ${await res.text()}`);
  const r = await res.json();
  return Array.isArray(r) ? r[0] : r;
}

async function supaPatch(table, id, data) {
  const res = await fetch(`${SUPA_URL}/rest/v1/${table}?id=eq.${id}`, {
    method: 'PATCH',
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}`,
      'Content-Type': 'application/json', Prefer: 'return=representation' },
    body: JSON.stringify(data)
  });
  if (!res.ok) throw new Error(`PATCH ${table} ${res.status}: ${await res.text()}`);
  const r = await res.json();
  return Array.isArray(r) ? r[0] : r;
}

async function supaUpsert(table, data) {
  const res = await fetch(`${SUPA_URL}/rest/v1/${table}`, {
    method: 'POST',
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}`,
      'Content-Type': 'application/json',
      Prefer: 'return=representation,resolution=merge-duplicates' },
    body: JSON.stringify(data)
  });
  if (!res.ok) throw new Error(`UPSERT ${table} ${res.status}: ${await res.text()}`);
  const r = await res.json();
  return Array.isArray(r) ? r[0] : r;
}

// ── Veeqo API ────────────────────────────────────────────────
let veeqoReqs = 0, veeqoWindowStart = Date.now();

async function veeqoGet(url) {
  veeqoReqs++;
  const elapsed = Date.now() - veeqoWindowStart;
  if (veeqoReqs >= 130 && elapsed < 60000) {
    const wait = 60000 - elapsed + 1000;
    console.log(`Veeqo rate pause ${Math.ceil(wait/1000)}s...`);
    await sleep(wait);
    veeqoReqs = 0; veeqoWindowStart = Date.now();
  }
  if (elapsed >= 60000) { veeqoReqs = 1; veeqoWindowStart = Date.now(); }

  const response = await this.helpers.httpRequestWithAuthentication.call(
    this, 'httpHeaderAuth',
    { method: 'GET', url, json: true, returnFullResponse: true }
  );

  if (response.statusCode === 429) {
    console.log('Veeqo 429, waiting 60s...');
    await sleep(60000);
    veeqoReqs = 0; veeqoWindowStart = Date.now();
    return veeqoGet.call(this, url);
  }
  return response.body;
}

// ── Tracking URL builder ─────────────────────────────────────
function buildTrackingUrl(tn, carrierName) {
  if (!tn) return null;
  tn = tn.trim();
  const c = (carrierName || '').toLowerCase();
  if (tn.startsWith('1Z') || c.includes('ups')) return 'https://www.ups.com/track?track=yes&trackNums=' + tn;
  if (c.includes('fedex') || /^\d{12,22}$/.test(tn)) return 'https://www.fedex.com/fedextrack/?trknbr=' + tn;
  if (c.includes('usps') || c.includes('stamps') || /^9\d{19,33}$/.test(tn)) return 'https://tools.usps.com/go/TrackConfirmAction?tLabels=' + tn;
  if (c.includes('ontrac') || /^[CD]\d{10,20}$/.test(tn)) return 'https://www.ontrac.com/tracking/?number=' + tn;
  if (tn.startsWith('TBA')) return 'https://track.amazon.com/tracking/' + tn;
  return 'https://aftership.com/track/' + tn;
}

// ── Status mappings ──────────────────────────────────────────
function mapOrderStatus(s) {
  const m = { awaiting_payment:'awaiting_payment', awaiting_fulfillment:'awaiting_fulfillment',
    partially_fulfilled:'partially_shipped', shipped:'shipped', delivered:'delivered',
    cancelled:'cancelled', on_hold:'on_hold', refunded:'refunded' };
  return m[s] || 'pending';
}
function mapShipmentStatus(t) {
  if (!t) return 'created';
  if (t.delivered_at) return 'delivered';
  if (t.out_for_delivery_at) return 'out_for_delivery';
  if (t.in_transit_at) return 'in_transit';
  if (t.awaiting_collection_at) return 'awaiting_collection';
  if (t.cancelled_at) return 'cancelled';
  if (t.returned_to_sender_at) return 'returned_to_sender';
  if (t.attempted_delivery_at) return 'attempted_delivery';
  return 'created';
}

// ── Step 1: Get cursor ───────────────────────────────────────
const cursorInput = $input.all();
let sinceDate = null;
if (cursorInput.length > 0) {
  const d = cursorInput[0].json;
  if (Array.isArray(d) && d.length > 0) sinceDate = d[0].cursor_value;
  else if (d?.cursor_value) sinceDate = d.cursor_value;
}
if (!sinceDate) {
  const d = new Date(); d.setDate(d.getDate() - 7);
  sinceDate = d.toISOString();
}
console.log(`Syncing Veeqo orders since ${sinceDate}`);

// ── Step 2: Warm caches ──────────────────────────────────────
const channelCache = {};
const warehouseCache = {};
const variantCache = {};
const costPriceCache = {};
const customerCache = {};

try {
  const channels = await supaGet('channels?select=id,external_id');
  for (const c of channels) if (c.external_id) channelCache[String(c.external_id)] = c.id;
  const warehouses = await supaGet('warehouses?select=id,external_id');
  for (const w of warehouses) if (w.external_id) warehouseCache[String(w.external_id)] = w.id;
  const variants = await supaGet('product_variants?select=id,sku,cost_price');
  for (const v of variants) if (v.sku) {
    variantCache[v.sku] = v.id;
    if (v.cost_price > 0) costPriceCache[v.sku] = +v.cost_price;
  }
  console.log(`Caches: ${Object.keys(channelCache).length} channels, ${Object.keys(warehouseCache).length} warehouses, ${Object.keys(variantCache).length} variants`);
} catch (e) { console.log('Cache warm error:', e.message); }

// ── Step 3: Fetch all orders from Veeqo ──────────────────────
let allOrders = [];
let page = 1;
while (true) {
  console.log(`Fetching orders page ${page}...`);
  const batch = await veeqoGet.call(this,
    `https://api.veeqo.com/orders?page_size=100&page=${page}&created_at_min=${sinceDate}`);
  if (!batch || !Array.isArray(batch) || batch.length === 0) break;
  allOrders = allOrders.concat(batch);
  console.log(`  Got ${batch.length} (total: ${allOrders.length})`);
  if (batch.length < 100) break;
  page++;
  if (page % 10 === 0) await sleep(1000);
}
console.log(`Fetched ${allOrders.length} orders total`);

if (allOrders.length === 0) {
  return [{ json: { message: 'No new orders', stats, sinceDate } }];
}

// ── Cost price fallback ──────────────────────────────────────
async function lookupCostPrice(sku) {
  if (costPriceCache[sku] !== undefined) return costPriceCache[sku];
  try {
    const rows = await supaGet(`order_items?sku=eq.${encodeURIComponent(sku)}&cost_price=gt.0&select=cost_price&limit=1`);
    const cost = rows?.[0]?.cost_price ? +rows[0].cost_price : 0;
    costPriceCache[sku] = cost;
    return cost;
  } catch { costPriceCache[sku] = 0; return 0; }
}

// ── Step 4: Process each order ───────────────────────────────
for (let i = 0; i < allOrders.length; i++) {
  const vo = allOrders[i];
  const veeqoId = String(vo.id);
  const orderNum = vo.number || veeqoId;

  if (i % 25 === 0) console.log(`Processing ${i+1}/${allOrders.length}: ${orderNum}`);

  try {
    // Check if order exists
    const existing = await supaGet(`orders?external_ids->>veeqo=eq.${veeqoId}&select=id,status&limit=1`);
    const existingId = existing?.[0]?.id;
    const existingStatus = existing?.[0]?.status;
    const newStatus = mapOrderStatus(vo.status);

    // Skip if unchanged (incremental)
    if (existingId && existingStatus === newStatus) {
      const nullTracking = await supaGet(`shipments?order_id=eq.${existingId}&tracking_number=is.null&select=id&limit=1`);
      if (!nullTracking?.length) { stats.skipped++; continue; }
    }

    // ── Customer ──
    let customerId = null;
    const cust = vo.customer;
    const deliverTo = vo.deliver_to;
    if (cust || deliverTo) {
      const email = cust?.email || deliverTo?.email || null;
      const firstName = cust?.full_name?.split(' ')[0] || deliverTo?.first_name || null;
      const lastName = cust?.full_name?.split(' ').slice(1).join(' ') || deliverTo?.last_name || null;
      const phone = cust?.phone || cust?.mobile || deliverTo?.phone || null;
      const cacheKey = email || `${firstName}_${lastName}`;

      if (customerCache[cacheKey]) {
        customerId = customerCache[cacheKey];
      } else {
        let custExisting = null;
        if (email) {
          const rows = await supaGet(`customers?email=eq.${encodeURIComponent(email)}&select=id&limit=1`);
          custExisting = rows?.[0]?.id;
        }
        const custData = {
          ...(custExisting ? { id: custExisting } : {}),
          first_name: firstName, last_name: lastName, email, phone,
          customer_type: cust?.customer_type || 'retail',
          channel_customer_ids: { veeqo: String(cust?.id || '') }
        };
        try {
          const r = await supaUpsert('customers', custData);
          customerId = r?.id || custExisting;
          if (customerId) customerCache[cacheKey] = customerId;
          if (!custExisting) stats.customers_created++;
        } catch (e) { stats.errors++; }
      }
    }

    // ── Addresses ──
    let shippingAddrId = null, billingAddrId = null;
    if (customerId) {
      for (const [addrData, type] of [[deliverTo, 'shipping'], [vo.billing_address, 'billing']]) {
        if (!addrData?.address1) continue;
        try {
          const addrExisting = await supaGet(
            `addresses?customer_id=eq.${customerId}&address_line_1=eq.${encodeURIComponent(addrData.address1)}&address_type=eq.${type}&select=id&limit=1`);
          const addrExistingId = addrExisting?.[0]?.id;
          const addr = {
            ...(addrExistingId ? { id: addrExistingId } : {}),
            customer_id: customerId, address_type: type,
            first_name: addrData.first_name || null, last_name: addrData.last_name || null,
            company: addrData.company || null,
            address_line_1: addrData.address1, address_line_2: addrData.address2 || null,
            city: addrData.city || addrData.city_locality || '',
            state: addrData.state || addrData.state_province || null,
            country: addrData.country || addrData.country_code || 'US',
            postal_code: addrData.zip || addrData.postal_code || '',
            phone: addrData.phone || null, email: addrData.email || null,
            is_verified: addrData.verified || false,
            is_residential: addrData.residential !== false
          };
          const r = await supaUpsert('addresses', addr);
          if (type === 'shipping') shippingAddrId = r?.id || addrExistingId;
          else billingAddrId = r?.id || addrExistingId;
        } catch (e) { stats.errors++; }
      }
    }

    // ── Order ──
    const channelId = channelCache[String(vo.channel?.id)] || null;
    const warehouseId = warehouseCache[String(vo.allocations?.[0]?.warehouse?.id)] || null;
    const orderData = {
      ...(existingId ? { id: existingId } : {}),
      order_number: orderNum, channel_id: channelId, customer_id: customerId,
      status: newStatus, shipping_address_id: shippingAddrId, billing_address_id: billingAddrId,
      subtotal: +(vo.subtotal_price || 0), shipping_cost: +(vo.delivery_cost || 0),
      tax_amount: +(vo.total_tax || 0), discount_amount: +(vo.total_discounts || 0),
      total: +(vo.total_price || 0), currency_code: vo.currency_code || 'USD',
      ordered_at: vo.created_at, shipped_at: vo.shipped_at || null,
      cancelled_at: vo.cancelled_at || null, warehouse_id: warehouseId,
      delivery_method: vo.delivery_method?.name || null,
      is_prime: vo.is_amazon_prime || false,
      fulfilled_by: vo.fulfilled_by_amazon ? 'fba' : 'merchant',
      customer_notes: vo.customer_note?.text || null,
      internal_notes: vo.notes || null,
      tags: (vo.tags || []).map(t => t.name),
      data_source: 'veeqo', external_ids: { veeqo: veeqoId }
    };
    let orderId;
    try {
      const r = await supaUpsert('orders', orderData);
      orderId = r?.id || existingId;
      existingId ? stats.orders_updated++ : stats.orders_created++;
    } catch (e) { stats.errors++; continue; }
    if (!orderId) { stats.errors++; continue; }

    // ── Line items (only on create) ──
    if (!existingId) {
      for (const li of (vo.line_items || [])) {
        const sku = li.sellable?.sku_code || 'UNKNOWN';
        try {
          await supaPost('order_items', {
            order_id: orderId, variant_id: variantCache[sku] || null, sku,
            title: li.title || li.sellable?.product_title || '',
            quantity: li.quantity || 1, unit_price: +(li.price_per_unit || 0),
            tax_rate: +(li.tax_rate || 0),
            tax_amount: +((li.price_per_unit||0) * (li.quantity||1) * (li.tax_rate||0)).toFixed(2),
            discount_amount: +(li.taxless_discount_per_unit || 0) * (li.quantity || 1),
            cost_price: +(li.sellable?.cost_price || 0) || await lookupCostPrice(sku),
            remote_line_id: li.remote_id ? String(li.remote_id) : null
          });
          stats.items_created++;
        } catch (e) {
          if (!e.message.includes('duplicate') && !e.message.includes('23505')) stats.errors++;
        }
      }
    }

    // ── Shipments ──
    for (const alloc of (vo.allocations || [])) {
      const ship = alloc.shipment;
      if (!ship) continue;
      const veeqoShipId = String(ship.id);
      const tracking = ship.tracking_number || ship.tracking || ship.trackings?.[0];
      const trackingNumber = tracking?.tracking_number || null;
      const carrierName = ship.carrier?.name || null;
      const carrierCode = ship.carrier?.slug || ship.carrier?.provider_type || null;

      const shipExisting = await supaGet(`shipments?external_ids->>veeqo=eq.${veeqoShipId}&select=id&limit=1`);
      const shipExistingId = shipExisting?.[0]?.id;

      const shipData = {
        ...(shipExistingId ? { id: shipExistingId } : {}),
        order_id: orderId, warehouse_id: warehouseId,
        status: mapShipmentStatus(tracking),
        label_source: carrierCode === 'buy-shipping' ? 'amazon_buy_shipping' : 'veeqo',
        data_source: 'veeqo', carrier_name: carrierName, carrier_code: carrierCode,
        carrier_service: ship.service_name || ship.short_service_name || null,
        service_code: ship.service_type || null,
        tracking_number: trackingNumber,
        tracking_url: buildTrackingUrl(trackingNumber, carrierName),
        label_created_at: ship.created_at || null,
        shipped_at: ship.created_at || ship.shipped_at || null,
        delivered_at: tracking?.delivered_at || null,
        label_cost: ship.outbound_label_charges?.value ?? (ship.cost ? +ship.cost : null),
        insurance_cost: ship.insurance_charges?.value ?? null,
        total_cost: (ship.outbound_label_charges?.value ?? 0) + (ship.insurance_charges?.value ?? 0) || null,
        weight_oz: alloc.total_weight || null,
        is_voided: tracking?.cancelled || false,
        voided_at: tracking?.cancelled_at || null,
        external_ids: { veeqo: veeqoShipId }
      };
      const pkg = alloc.allocation_package;
      if (pkg) {
        shipData.length_in = pkg.depth || null;
        shipData.width_in = pkg.width || null;
        shipData.height_in = pkg.height || null;
        shipData.package_type = pkg.package_name || null;
      }

      try {
        const r = await supaUpsert('shipments', shipData);
        const shipmentId = r?.id || shipExistingId;
        if (!shipExistingId) stats.shipments_created++;

        // Tracking events
        if (shipmentId && tracking && trackingNumber) {
          const tsFields = [
            ['created', 'Label created', tracking.created_at],
            ['awaiting_collection', 'Awaiting collection', tracking.awaiting_collection_at],
            ['in_transit', 'In transit', tracking.in_transit_at],
            ['out_for_delivery', 'Out for delivery', tracking.out_for_delivery_at],
            ['delivered', 'Delivered', tracking.delivered_at],
            ['attempted_delivery', 'Delivery attempted', tracking.attempted_delivery_at],
            ['returned_to_sender', 'Returned to sender', tracking.returned_to_sender_at],
            ['cancelled', 'Cancelled', tracking.cancelled_at]
          ];
          for (const [status, desc, ts] of tsFields) {
            if (!ts) continue;
            try {
              await supaUpsert('tracking_events', {
                shipment_id: shipmentId, tracking_number: trackingNumber,
                status, description: desc, occurred_at: ts
              });
              stats.tracking_events++;
            } catch (e) { /* dedup via unique constraint */ }
          }
        }
      } catch (e) { stats.errors++; }
    }
  } catch (e) {
    stats.errors++;
    if (stats.errors <= 10) console.log(`Error order ${orderNum}: ${e.message}`);
  }
}

// ── Step 5: Update sync cursor ───────────────────────────────
const now = new Date().toISOString();
try {
  const cursorExisting = await supaGet('sync_cursors?source=eq.veeqo_orders&select=id&limit=1');
  if (cursorExisting?.[0]?.id) {
    await supaPatch('sync_cursors', cursorExisting[0].id, {
      cursor_value: now, last_synced_at: now,
      records_synced: stats.orders_created + stats.orders_updated,
      metadata: { stats }
    });
  } else {
    await supaPost('sync_cursors', {
      source: 'veeqo_orders', cursor_value: now, last_synced_at: now,
      records_synced: stats.orders_created + stats.orders_updated,
      metadata: { stats }
    });
  }
} catch (e) { console.log('Cursor update error:', e.message); }

console.log('\n════════════════════════════════');
console.log('Sync complete!');
console.log(`  Orders created:  ${stats.orders_created}`);
console.log(`  Orders updated:  ${stats.orders_updated}`);
console.log(`  Skipped:         ${stats.skipped}`);
console.log(`  Customers:       ${stats.customers_created}`);
console.log(`  Items:           ${stats.items_created}`);
console.log(`  Shipments:       ${stats.shipments_created}`);
console.log(`  Tracking:        ${stats.tracking_events}`);
console.log(`  Errors:          ${stats.errors}`);

return [{ json: { message: 'Sync complete', stats, sinceDate } }];
